def fit_to_budget(text, budget=280):
    if len(text) <= budget:
        return text
    # Truncate at budget characters, then back up to the last space
    truncated = text[:budget]
    last_space = truncated.rfind(' ')
    if last_space == -1:
        # No space found; can't avoid cutting a word — return hard truncation
        return truncated
    return truncated[:last_space]

