    if last_space == -1:
        # No space within budget; no choice but to truncate mid-word.
        return truncated
    return truncated[:last_space]

def fit_to_budget(text, budget=280):
    """Shorten text so it fits within budget characters without cutting a word in half."""
    if len(text) <= budget:
        return text

    truncated = text[:budget]

    if text[budget] != ' ':
        last_space = truncated.rfind(' ')
        if last_space == -1:
            return ''
        truncated = truncated[:last_space]
    else:
        truncated = truncated.rstrip(' ')

    return truncated

