from urllib.parse import urlparse


def extract_domain(url: str) -> str:
    """
    Extract the registrable (base) domain from a URL.
    Strips scheme, userinfo, port, path, query, and subdomains.
    Returns lowercased result.
    """
    # Parse the URL to get the netloc/hostname
    parsed = urlparse(url)
    hostname = parsed.hostname  # returns lowercase, strips port and userinfo

    if not hostname:
        # Maybe it was passed without a scheme - try adding one
        parsed = urlparse("http://" + url)
        hostname = parsed.hostname

    if not hostname:
        return url.lower()

    # If hostname is an IPv4 address, return it as-is
    if re.match(r'^\d+\.\d+\.\d+\.\d+$', hostname):
        return hostname

    parts = hostname.split(".")

    # Known multi-part TLDs (second-level TLDs)
    MULTI_TLDS = {
        "co.uk", "co.nz", "co.jp", "co.za", "co.in", "co.kr",
        "com.au", "com.br", "com.cn", "com.mx", "com.ar", "com.sg",
        "org.uk", "net.uk", "gov.uk", "ac.uk", "me.uk",
        "gov.au", "net.au", "org.au",
        "ne.jp", "or.jp", "ac.jp", "ad.jp", "ed.jp", "go.jp",
        "or.kr", "pe.kr",
    }

    if len(parts) >= 3:
        # Check if last two parts form a known multi-part TLD
        potential_tld = ".".join(parts[-2:])
        if potential_tld in MULTI_TLDS:
            # Keep last 3 parts: domain + 2-part TLD
            return ".".join(parts[-3:])

    # Default: keep last 2 parts
    if len(parts) >= 2:
        return ".".join(parts[-2:])

    return hostname

from urllib.parse import urlparse


def extract_domain(url: str) -> str:
    """Return the registrable (base) domain from a URL, lowercased."""
    # Parse the URL; if no scheme, add a dummy one so urlparse works
    if "://" not in url:
        parsed = urlparse("http://" + url)
    else:
        parsed = urlparse(url)

    # Get the hostname (strips port and userinfo, lowercases)
    hostname = parsed.hostname or ""

    # Strip subdomains: keep only the last two labels (registrable domain)
    parts = hostname.split(".")
    if len(parts) > 2:
        # Handle known two-part TLDs like co.uk, com.au, etc.
        two_part_tlds = {
            "co.uk", "co.jp", "co.nz", "co.za", "co.in", "co.kr",
            "com.au", "com.br", "com.cn", "com.mx", "com.ar", "com.sg",
            "org.uk", "net.au", "gov.uk", "gov.au", "ac.uk", "edu.au",
        }
        last_two = ".".join(parts[-2:])
        if last_two in two_part_tlds:
            # registrable domain = label + two-part TLD
            return ".".join(parts[-3:]) if len(parts) >= 3 else hostname
        else:
            return ".".join(parts[-2:])

    return hostname

