try:
    import tldextract as _tldextract
    _USE_TLDEXTRACT = True
except ImportError:
    _USE_TLDEXTRACT = False


def extract_domain(url: str) -> str:
    """Return the registrable (base) domain from a URL.

    Strips scheme, userinfo, port, path, query, and subdomains, and returns
    the result lowercased. Uses the Public Suffix List via tldextract when
    available; otherwise falls back to the last two hostname labels.
    """
    if "://" not in url:
        url = "http://" + url

    if _USE_TLDEXTRACT:
        extracted = _tldextract.extract(url)
        domain = extracted.domain
        suffix = extracted.suffix
        if domain and suffix:
            return f"{domain}.{suffix}".lower()
        if domain:
            return domain.lower()
        # Bare IP or localhost-like: fall through to hostname
        parsed = urlparse(url)
        return (parsed.hostname or "").lower()

    # Fallback: strip subdomains by keeping the last two labels
    parsed = urlparse(url)
    hostname = (parsed.hostname or "").lstrip(".")
    parts = hostname.split(".")
    if len(parts) >= 2:
        return ".".join(parts[-2:])
    return hostname

import tldextract


def extract_domain(url: str) -> str:
    """Return the registrable (base) domain from a URL, lowercased.

    Strips scheme, userinfo, port, path, query, and any subdomains.
    Uses tldextract for correct public-suffix handling (e.g. bbc.co.uk).
    """
    extracted = tldextract.extract(url)
    if extracted.domain and extracted.suffix:
        return f"{extracted.domain}.{extracted.suffix}".lower()
    # Fallback for bare hostnames with no recognised suffix
    if extracted.domain:
        return extracted.domain.lower()
    if extracted.suffix:
        return extracted.suffix.lower()
    return ""

def is_valid_feed_item(item):
    if not isinstance(item, dict):
        return False
    title = item.get("title")
    url = item.get("url")
    ts = item.get("ts")
    # title must be a non-empty string
    if not isinstance(title, str) or not title.strip():
        return False
    # url must be a non-empty string
    if not isinstance(url, str) or not url.strip():
        return False
    # ts must be present and truthy (non-zero number or non-empty string)
    if ts is None or ts == "" or ts == 0:
        return False
    return True
